module.render:
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;')
  .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const errBox = (msg) => '\n\n<div style="color:#b91c1c; border:1px solid #b91c1c; padding:0.6em 0.9em; '
  + 'border-radius:6px; font-size:0.95em;"><strong>QR module:</strong> ' + esc(msg) + '</div>\n\n';

// Data to encode = the BODY (raw, so commas / quotes / & survive). When the
// body is empty, fall back to the `text` param, then a sample placeholder.
const body = (sections[0] != null) ? String(sections[0]).trim() : '';
const fallback = (args.text != null && String(args.text).trim() !== '') ? String(args.text).trim() : '';
const text = body || fallback || 'https://example.com';
const caption = (args.caption != null) ? String(args.caption).trim() : '';
const ecRaw = String(args.ec || 'M').toUpperCase();
const ec = (['L', 'M', 'Q', 'H'].indexOf(ecRaw) >= 0) ? ecRaw : 'M';
const pxN = parseInt(args.size, 10);
const px = (pxN > 0) ? Math.max(48, Math.min(800, pxN)) : 180;
let marginN = parseInt(args.margin, 10);
const margin = isNaN(marginN) ? 4 : Math.max(0, Math.min(16, marginN));
const dark = (args.dark && String(args.dark).trim()) || '#000000';
const light = (args.light && String(args.light).trim()) || '#ffffff';
const alignRaw = String(args.align || 'center').toLowerCase();
const align = (['left', 'center', 'right'].indexOf(alignRaw) >= 0) ? alignRaw : 'center';

const gen = (typeof window !== 'undefined') ? window.mdpCreateQR : undefined;
if (typeof gen !== 'function') {
  return errBox('QR generator is unavailable — update the MDP app to a version that provides it.');
}

let m;
try { m = gen(text, { errorCorrectionLevel: ec }); }
catch (e) { return errBox('Cannot encode this text (' + (e && e.message ? e.message : 'too long for a QR code') + ').'); }

const n = m.size, data = m.data, total = n + margin * 2;
let d = '';
for (let r = 0; r < n; r++) {
  for (let c = 0; c < n; c++) {
    if (data[r * n + c]) { d += 'M' + (c + margin) + ' ' + (r + margin) + 'h1v1h-1z'; }
  }
}

const bg = (light === 'transparent') ? '' : '<rect width="' + total + '" height="' + total + '" fill="' + light + '"/>';
const svg = '<svg class="mdp-qr-svg" viewBox="0 0 ' + total + ' ' + total + '"'
  + ' width="' + px + '" height="' + px + '" shape-rendering="crispEdges" role="img"'
  + ' aria-label="' + esc(text) + '" xmlns="http://www.w3.org/2000/svg">'
  + bg + '<path d="' + d + '" fill="' + dark + '"/></svg>';

const cap = caption ? '<div class="mdp-qr-caption">' + esc(caption) + '</div>' : '';
return '\n\n<div class="mdp-mod-qr" style="text-align:' + align + ';">'
  + '<div class="mdp-qr-frame" style="width:' + px + 'px;">' + svg + cap + '</div></div>\n\n';
